import asyncio
import websockets
import json
import uuid

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.inventory = {}

    def add_item(self, item_id, quantity=1):
        if item_id in self.inventory:
            self.inventory[item_id] += quantity
        else:
            self.inventory[item_id] = quantity

    def remove_item(self, item_id, quantity=1):
        if item_id in self.inventory and self.inventory[item_id] >= quantity:
            self.inventory[item_id] -= quantity
            if self.inventory[item_id] == 0:
                del self.inventory[item_id]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def register_player(self, player_id):
        async with self.lock:
            if player_id not in self.players:
                self.players[player_id] = Player(player_id)

    async def handle_trade(self, sender_id, receiver_id, item_id, quantity):
        async with self.lock:
            sender = self.players.get(sender_id)
            receiver = self.players.get(receiver_id)
            if sender and receiver and sender.remove_item(item_id, quantity):
                receiver.add_item(item_id, quantity)
                return True
            return False

    async def handle_client(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            action = data.get("action")
            player_id = data.get("player_id")

            if action == "register":
                await self.register_player(player_id)
                await websocket.send(json.dumps({"status": "registered"}))

            elif action == "trade":
                sender_id = data.get("sender_id")
                receiver_id = data.get("receiver_id")
                item_id = data.get("item_id")
                quantity = data.get("quantity", 1)

                success = await self.handle_trade(sender_id, receiver_id, item_id, quantity)
                if success:
                    await websocket.send(json.dumps({"status": "trade_success"}))
                else:
                    await websocket.send(json.dumps({"status": "trade_failed"}))

    async def start_server(self, host='localhost', port=8765):
        async with websockets.serve(self.handle_client, host, port):
            await asyncio.Future()

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())